-- View 1) Beds_info
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `beds_info` AS select count(`be`.`bed_id`) AS `beds`,`ro`.`room_type` AS `room_type`,`be`.`status` AS `status`,`ro`.`room_id` AS `room_id` from (`beds` `be` left join `rooms` `ro` on((`be`.`room_id` = `ro`.`room_id`))) group by `ro`.`room_type`,`be`.`status`,`ro`.`room_id`;

-- View 2) Patients_info
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `patient_info` AS select `p`.`patient_id` AS `patient_patient_id`,`p`.`name` AS `patient_name`,`p`.`gender` AS `patient_gender`,`p`.`weight` AS `patient_weight`,`p`.`age` AS `patient_age`,`p`.`blood_group` AS `patient_blood_group`,`p`.`email` AS `patient_email`,`p`.`admission_date` AS `patient_admission_date`,`p`.`discharge_date` AS `patient_discharge_date`,`p`.`Img` AS `patient_Img`,`p`.`address` AS `patient_address`,`p`.`status` AS `patient_status`,(case when (`b`.`bed_id` is null) then 'Discharged' else 'Admitted' end) AS `patient_admission_status`,`dr`.`doctor_id` AS `doctor_doctor_id`,`dr`.`name` AS `doctor_name`,`dr`.`salary` AS `doctor_salary`,`dr`.`specialization` AS `doctor_specialization`,`dr`.`department` AS `doctor_department`,`dr`.`availability` AS `doctor_availability`,`dr`.`joining_date` AS `doctor_joining_date`,`dr`.`qualification` AS `doctor_qualification`,`dr`.`Img` AS `doctor_Img`,`dr`.`experience_years` AS `doctor_experience_years`,`dr`.`email` AS `doctor_email`,`dr`.`phone` AS `doctor_phone`,`b`.`bed_id` AS `bed_bed_id`,`b`.`occupied_from` AS `bed_occupied_from`,`b`.`occupied_till` AS `bed_occupied_till`,`b`.`status` AS `bed_status`,`r`.`room_id` AS `room_room_id`,`r`.`floor` AS `room_floor`,`r`.`room_type` AS `room_room_type`,`r`.`capacity` AS `room_capacity`,`r`.`daily_charge` AS `room_daily_charge`,`r`.`avg_montly_maintenance_cost` AS `room_avg_montly_maintenance_cost`,`r`.`status` AS `room_status`,`d`.`department_id` AS `department_department_id`,`d`.`name` AS `department_name`,`d`.`total_staff` AS `department_total_staff`,`s`.`satisfaction_id` AS `satisfaction_satisfaction_id`,`s`.`rating` AS `satisfaction_rating`,`s`.`feedback` AS `satisfaction_feedback`,`sur`.`appointment_id` AS `surgery_appointment_id`,`sur`.`appointment_date` AS `surgery_appointment_date`,`sur`.`appointment_time` AS `surgery_appointment_time`,`sur`.`status` AS `surgery_status`,`sur`.`reason` AS `surgery_reason`,`sur`.`notes` AS `surgery_notes` from (((((((`patient` `p` left join `satisfaction_score` `s` on((`p`.`patient_id` = `s`.`patient_id`))) left join `surgery` `sur` on((`sur`.`patient_id` = `p`.`patient_id`))) left join `beds` `b` on((`b`.`patient_id` = `p`.`patient_id`))) left join `rooms` `r` on((`r`.`room_id` = `b`.`room_id`))) left join `department` `d` on((`d`.`department_id` = `r`.`department_id`))) left join (select distinct `appointment`.`patient_id` AS `patient_id`,`appointment`.`doctor_id` AS `doctor_id` from `appointment`) `a` on((`a`.`patient_id` = `p`.`patient_id`))) left join `doctor` `dr` on((`dr`.`doctor_id` = `a`.`doctor_id`)));

-- View 3) Medical_Stock_info
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `medical_stock_info` AS select `m`.`medicine_id` AS `medicine_id`,`m`.`name` AS `name`,`m`.`category` AS `category`,`m`.`supplier_id` AS `supplier_id`,`m`.`cost_price` AS `cost_price`,`m`.`unit_price` AS `unit_price`,`m`.`stock_qty` AS `stock_qty`,`m`.`expiry_date` AS `expiry_date`,`m`.`manufacture_date` AS `manufacture_date`,`m`.`batch_number` AS `batch_number`,`m`.`reorder_level` AS `reorder_level`,`s`.`name` AS `supplier_name` from (`medical_stock` `m` left join `supplier` `s` on((`m`.`supplier_id` = `s`.`supplier_id`)));
